// в•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—
// в•‘   TaskBarHero вҖ” Frida Hile AyarlarДұ ve KodlarДұ           в•‘
// в•‘   Yazar: Pantheon                                        в•‘
// в•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ

// ==============================================================================
// вҡҷпёҸ HД°LE AYARLARI (Д°stediДҹiniz deДҹerleri buradan deДҹiЕҹtirebilirsiniz)
// ==============================================================================
const GODMODE      = true;      // true: Г–lГјmsГјzlГјk AГ§Дұk  | false: KapalДұ
const ONE_HIT_KILL = true;      // true: Tek Atma AГ§Дұk   | false: KapalДұ
const OHK_HASAR    = 9000.0;  // DГјЕҹmana verilecek hasar miktarДұ (ArttДұrabilirsiniz)

// ==============================================================================
// рҹӣ пёҸ OYUN OFSETLERД° VE KODLARI (v2.5 yamasДұ iГ§in gГјncel hasar alma fonksiyonlarДұ)
// ==============================================================================
const RVA_HERO_GQM    = 0xC00CE0; // Hero.gqm metot adresi (KahramanДұn hasar aldДұДҹДұ yer)
const RVA_MONSTER_GQM = 0xC05780; // Monster.gqm metot adresi (CanavarlarДұn hasar aldДұДҹДұ yer)
const OFF_DAMAGE      = 0x08;     // DamageInfo->OriginDamage ofseti (float)

function banner() {
    console.log('\n\x1b[36mв•”в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•—\x1b[0m');
    console.log('\x1b[36mв•‘   TaskBarHero Hook Script v2.5 вҖў Pantheon        в•‘\x1b[0m');
    console.log('\x1b[36mв•‘   Frida SГјrГјmГј: ' + Frida.version.padEnd(32) + ' в•‘\x1b[0m');
    console.log('\x1b[36mв• в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•Ј\x1b[0m');
    console.log('в•‘  Godmode      : ' + (GODMODE      ? '\x1b[32mвң” AГҮIK \x1b[0m' : '\x1b[31mвңҳ KAPALI\x1b[0m') + '                        в•‘');
    console.log('в•‘  One Hit Kill : ' + (ONE_HIT_KILL ? '\x1b[32mвң” AГҮIK \x1b[0m' : '\x1b[31mвңҳ KAPALI\x1b[0m') + '  (' + String(OHK_HASAR).padEnd(10) + ' hasar)  в•‘');
    console.log('\x1b[36mв•ҡв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•қ\x1b[0m\n');
}

banner();

const mod = Process.findModuleByName('GameAssembly.dll');
if (!mod) {
    console.log('[-] GameAssembly.dll bulunamadДұ вҖ” oyun aГ§Дұk mДұ?');
} else {
    console.log('[+] GameAssembly.dll @ ' + mod.base);

    // 1. Kahraman Hasar KontrolГј (Godmode)
    try {
        Interceptor.attach(mod.base.add(RVA_HERO_GQM), {
            onEnter(args) {
                if (GODMODE) {
                    const dmgInf = args[1];
                    if (!dmgInf.isNull()) {
                        dmgInf.add(OFF_DAMAGE).writeFloat(0.0); // Kahramana gelen hasarДұ 0 yap
                        console.log('[вң”] Godmode вҖ” Kahramana gelen hasar engellendi.');
                    }
                }
            }
        });
        console.log('[+] Hook Aktif: Hero.gqm (Godmode)');
    } catch (err) {
        console.log('[-] Hero.gqm kancalanamadДұ: ' + err.message);
    }

    // 2. Canavar Hasar KontrolГј (One-Hit Kill)
    try {
        Interceptor.attach(mod.base.add(RVA_MONSTER_GQM), {
            onEnter(args) {
                if (ONE_HIT_KILL) {
                    const dmgInf = args[1];
                    if (!dmgInf.isNull()) {
                        dmgInf.add(OFF_DAMAGE).writeFloat(OHK_HASAR); // Canavara giden hasarДұ OHK yap
                        console.log('[вң”] One Hit Kill вҖ” DГјЕҹmana yГјksek hasar verildi.');
                    }
                }
            }
        });
        console.log('[+] Hook Aktif: Monster.gqm (One-Hit Kill)');
    } catch (err) {
        console.log('[-] Monster.gqm kancalanamadДұ: ' + err.message);
    }
}
